module priority_encoder (
    input [3:0] in,
    output reg [1:0] invalid_code
);

    always @(*) begin
        if (in[3]) begin
            invalid_code = 2'b11;
        end else if (in[2]) begin
            invalid_code = 2'b10;
        end else if (in[1]) begin
            invalid_code = 2'b01;
        end else if (in[0]) begin
            invalid_code = 2'b00;
        end else begin
            invalid_code = 2'b00;
        end
    end
endmodule
